      background-color: @surface0;
      color: @text;
      /* File preview (separate tab) No preview available Download */
      .ndfHFb-c4YZDc-bN97Pc-nupQLb-LgbsSe,
      .a-b-x-rb-d /* File preview (in Drive) No preview available Download */ {
        background-color: @surface1;
        color: @text;
        text-shadow: none;
        border-color: transparent;
        &:hover {
          background-color: @surface2;
          background-image: none;
        }
      }
      /* File preview (separate tab) No preview available Download icon */
      .ndfHFb-c4YZDc-bN97Pc-nupQLb-LgbsSe-Bz112c,
      .a-b-x-rb-d-c /* File preview (in Drive) No preview available Download icon */
      {
        & when (@flavor = latte) {
          filter: brightness(0) invert(31%) sepia(10%) saturate(1268%)
            hue-rotate(196deg) brightness(90%) contrast(86%);
        }
        & when (@flavor = frappe) {
          filter: brightness(0) invert(80%) sepia(7%) saturate(1070%)
            hue-rotate(192deg) brightness(104%) contrast(92%);
        }
        & when (@flavor = macchiato) {
          filter: brightness(0) invert(84%) sepia(13%) saturate(579%)
            hue-rotate(193deg) brightness(99%) contrast(94%);
        }
        & when (@flavor = mocha) {
          filter: brightness(0) invert(84%) sepia(19%) saturate(370%)
            hue-rotate(192deg) brightness(98%) contrast(95%);
        }
      }
    }
    /* File preview (in Drive) text document */
    .a-b-r-x,
    .ndfHFb-c4YZDc-fmcmS-bN97Pc /* File preview (separate tab) text document */
    {
      &,
      pre {
        background-color: @surface0 !important;
        color: @text !important;
      }
    }
    /* File preview (in Drive) comment on image */
    .Yk-efwuC {
      background-color: @surface0 !important;
      /* File preview (in Drive) comment on image person */
      .Yk-Vq7Udc {
        background-color: @surface0 !important;
        [data-name] {
          color: @text !important;
        }
        /* Comment text */
        .Yk-eKrold-Sg.Yk-eKrold-Sg {
          color: @text !important;
        }
        /* Comment date */
        .Yk-eKrold-bi {
          color: @subtext0 !important;
        }
      }
      /* File preview (in Drive) comments */
      .Yk-efwuC-vb-Gd {
        background-color: @surface0;
        &,
        * {
          color: @text !important;
        }
        [role="textbox"] {
          background-color: @surface1;
          border-color: @overlay0;
          &::before {
            color: @subtext0 !important;
          }
        }
        [role="button"] {
          background-color: @surface1 !important;
          /* needed to override border-color */
          &[role="button"] {
            border-color: @overlay0 !important;
          }
          &[aria-disabled="true"] {
            background-color: @surface1 !important;
            color: @subtext0 !important;
          }
        }
      }
    }

    /* Drive sharing window material icon */
    .SbpzSe .VfPpkd-StrnGf-rymPhb-f7MjDc {
      color: @accent;
    }

    /* Drive sharing window access hover */
    .lfDNBb:hover,
    .lfDNBb:focus-within,
    .ZelW3e:hover .FYhd9e,
    .ZelW3e:focus-within .FYhd9e /* Drive sharing window person row hover */ {
      background-color: @surface0;
    }

    /* Drive sharing iframe (in Drive) */
    .lb-k-x {
      color-scheme: unset;
    }
    /* Drive sharing iframe (file preview separate tab) */
    .XKSfm-Sx9Kwc-bN97Pc {
      color-scheme: auto; /* unset doesn't work? */
    }
    [role="tooltip"],
    .Kk7lMc-Ca /* Drive applications sidebar tooltip */,
    .gb_2e /* Drive google account tooltip */ {
      background-color: @surface2;
      *,
      & {
        color: @text !important;
      }
      border-color: transparent;
      /* File preview (separate tab) tooltip arrow */
      .tk3N6e-suEOdc-jQ8oHc,
      .tk3N6e-suEOdc-ez0xG {
        border-color: @surface2 transparent !important;
      }
    }

    /* Drive applications sidebar close button */
    .Kk7lMc-QWPxkf-d-j .Yb-Il-d .Yb-Il-d-c-j {
      background-color: @surface0;
      path:nth-child(1) {
        stroke: @text;
      }
    }
    /* Drive applications sidebar get addons */
    .Yb-Il-d#qJTzr .Yb-Il-d-c-j {
      & when (@flavor = latte) {
        filter: brightness(0) invert(31%) sepia(10%) saturate(1268%) hue-rotate(
          196deg
        ) brightness(90%) contrast(86%);
      }
      & when (@flavor = frappe) {
        filter: brightness(0) invert(80%) sepia(7%) saturate(1070%) hue-rotate(
          192deg
        ) brightness(104%) contrast(92%);
      }
      & when (@flavor = macchiato) {
        filter: brightness(0) invert(84%) sepia(13%) saturate(579%) hue-rotate(
          193deg
        ) brightness(99%) contrast(94%);
      }
      & when (@flavor = mocha) {
        filter: brightness(0) invert(84%) sepia(19%) saturate(370%) hue-rotate(
          192deg
        ) brightness(98%) contrast(95%);
      }
    }
    /* Drive applications sidebar close button white background */
    .Yb-Il-d-c-Nd {
      background-color: transparent;
    }

    /* Drive icon */
    [src="//ssl.gstatic.com/images/branding/product/1x/drive_2020q4_48dp.png"] {
      @darkBlue: mix(@blue, @base, 80%);
      @darkGreen: mix(@green, @base, 80%);

      @svg: escape(
        '<svg viewBox="0 0 87.3 78" xmlns="http://www.w3.org/2000/svg"><path d="m6.6 66.85 3.85 6.65c.8 1.4 1.95 2.5 3.3 3.3L27.5 53H0c0 1.55.4 3.1 1.2 4.5z" fill="@{darkBlue}"/><path d="M43.65 25 29.9 1.2c-1.35.8-2.5 1.9-3.3 3.3l-25.4 44A9.06 9.06 0 0 0 0 53h27.5z" fill="@{green}"/><path d="M73.55 76.8c1.35-.8 2.5-1.9 3.3-3.3l1.6-2.75L86.1 57.5c.8-1.4 1.2-2.95 1.2-4.5H59.798l5.852 11.5z" fill="@{red}"/><path d="M43.65 25 57.4 1.2C56.05.4 54.5 0 52.9 0H34.4c-1.6 0-3.15.45-4.5 1.2z" fill="@{darkGreen}"/><path d="M59.8 53H27.5L13.75 76.8c1.35.8 2.9 1.2 4.5 1.2h50.8c1.6 0 3.15-.45 4.5-1.2z" fill="@{blue}"/><path d="m73.4 26.5-12.7-22c-.8-1.4-1.95-2.5-3.3-3.3L43.65 25 59.8 53h27.45c0-1.55-.4-3.1-1.2-4.5z" fill="@{yellow}"/></svg>'
      );
      content: url("data:image/svg+xml,@{svg}");
    }

    /* Drive upload checkmark */
    .z-Ea-Fj-c svg path {
      fill: @green;
    }
  }
}

