      --surface-5: @surface2;

      --color-text-primary: @text;
      --color-text-default: @subtext1;
      --color-text-tertiary: @subtext0;
    }
  }
}

/* ==UserStyle==
@name NixOS Manual/Nixpkgs Manual Catppuccin
@namespace github.com/catppuccin/userstyles/styles/nixos-manual
@homepageURL https://github.com/catppuccin/userstyles/tree/main/styles/nixos-manual
@version 2025.09.06
@updateURL https://github.com/catppuccin/userstyles/raw/main/styles/nixos-manual/catppuccin.user.less
@supportURL https://github.com/catppuccin/userstyles/issues?q=is%3Aopen+is%3Aissue+label%3Anixos-manual
@description Soothing pastel theme for NixOS Manual and Nixpkgs Manual
@author Catppuccin
@license MIT

@preprocessor less
@var select lightFlavor "Light Flavor" ["latte:Latte*", "frappe:Frappé", "macchiato:Macchiato", "mocha:Mocha"]
@var select darkFlavor "Dark Flavor" ["latte:Latte", "frappe:Frappé", "macchiato:Macchiato", "mocha:Mocha*"]
@var select accentColor "Accent" ["rosewater:Rosewater", "flamingo:Flamingo", "pink:Pink", "mauve:Mauve*", "red:Red", "maroon:Maroon", "peach:Peach", "yellow:Yellow", "green:Green", "teal:Teal", "blue:Blue", "sapphire:Sapphire", "sky:Sky", "lavender:Lavender", "subtext0:Gray"]
==/UserStyle== */

@import "https://userstyles.catppuccin.com/lib/lib.less";

@-moz-document url-prefix("https://nixos.org/manual/"),
  url-prefix("https://nix-darwin.github.io/nix-darwin/manual/") {
  @import url("https://unpkg.com/@catppuccin/highlightjs@1.0.0/css/catppuccin-variables.important.css");

  :root {
    @media (prefers-color-scheme: light) {
      #catppuccin(@lightFlavor);
    }
    @media (prefers-color-scheme: dark) {
      #catppuccin(@darkFlavor);
    }
  }

  #catppuccin(@flavor) {
    #lib.palette();
    #lib.defaults();
    #lib.css-variables();

    --background: @base;
    --main-text-color: @text;
    --link-color: @accent;
    --heading-color: @accent;
    --small-heading-color: fade(@accent, 85%);
    --note-text-color: @blue;
    --note-background: @base;
    --warning-text-color: @red;
    --warning-background: @base;
    --codeblock-background: @surface0;
    --codeblock-text-color: @text;

    div.book .programlisting,
    div.appendix .programlisting {
      background-color: @surface0 !important;
    }

    hr,
    div.toc {
      border-top-color: transparent;
      border-bottom-color: @overlay1 !important;
    }

    // Version selector
    div[style^="background: #333333;color: #FFFFFF;"] {
      background-color: @crust !important;

      &,
      dt {
        color: @text !important;
      }

      a {
        color: @accent !important;
      }
    }
  }
}

/* ==UserStyle==
