==/UserStyle== */

@import "https://userstyles.catppuccin.com/lib/lib.less";

@-moz-document domain("search.nixos.org") {
  :root:not([data-theme]) {
    @media (prefers-color-scheme: light) {
      #catppuccin(@lightFlavor);
    }
    @media (prefers-color-scheme: dark) {
      #catppuccin(@darkFlavor);
    }
  }

  :root[data-theme="dark"] {
    #catppuccin(@darkFlavor);
  }

  :root[data-theme="light"] {
    #catppuccin(@lightFlavor);
  }

  #catppuccin(@flavor) {
    #lib.palette();
    #lib.defaults();

    --background-color: @base;
    --badge-background: @surface2;
    --button-active-background: @surface1;
    --button-active-hover-background: @surface2;
    --button-background: @surface0;
    --button-hover-background: @surface2;
    --color-active-hover-tab: @surface1;
    --color-active-tab: @surface0;
    --color-hover-tab: @surface1;
    --headerbar-background-color: @mantle;
    --hover-background: @surface0;
    --link-color: @accent;
    --info-label-background: @accent;
    --dark-blue: @accent;
    --light-blue: @accent; // used by focus outline
    --line-color: @surface0;
    --search-result-short-details-color: @subtext1;
    --search-result-divider-line-color: @surface0;
    --search-result-title-color: @accent;
    --search-sidebar-link-color: @text;
    --search-sidebar-selected-link-background: @accent;
    --search-sidebar-selected-link-color: @crust;
    --terminal-background: @surface0;
    --terminal-color: @text;
    --text-color: @text;
    --text-color-light: @text;
    --text-color-warning: @yellow;

    .badge {
      color: @text;
    }
    /* Experimental Flakes label */
    .label {
      color: @base;
      text-shadow: none;
    }
  }
}

/* ==UserStyle==
@name Ollama Catppuccin
@namespace github.com/catppuccin/userstyles/styles/ollama
@homepageURL https://github.com/catppuccin/userstyles/tree/main/styles/ollama
@version 2025.09.06
@updateURL https://github.com/catppuccin/userstyles/raw/main/styles/ollama/catppuccin.user.less
@supportURL https://github.com/catppuccin/userstyles/issues?q=is%3Aopen+is%3Aissue+label%3Aollama
@description Soothing pastel theme for Ollama
@author Catppuccin
@license MIT

@preprocessor less
@var select lightFlavor "Light Flavor" ["latte:Latte*", "frappe:Frappé", "macchiato:Macchiato", "mocha:Mocha"]
@var select darkFlavor "Dark Flavor" ["latte:Latte", "frappe:Frappé", "macchiato:Macchiato", "mocha:Mocha*"]
@var select accentColor "Accent" ["rosewater:Rosewater", "flamingo:Flamingo", "pink:Pink", "mauve:Mauve*", "red:Red", "maroon:Maroon", "peach:Peach", "yellow:Yellow", "green:Green", "teal:Teal", "blue:Blue", "sapphire:Sapphire", "sky:Sky", "lavender:Lavender", "subtext0:Gray"]
==/UserStyle== */

@import "https://userstyles.catppuccin.com/lib/lib.less";

@-moz-document domain("ollama.com") {
  @import url("https://unpkg.com/@catppuccin/highlightjs@1.0.0/css/catppuccin-variables.css");

  :root {
    @media (prefers-color-scheme: light) {
      #catppuccin(@lightFlavor);
    }
    @media (prefers-color-scheme: dark) {
      #catppuccin(@darkFlavor);
    }
  }

  #catppuccin(@flavor) {
    #lib.palette();
    #lib.defaults();
    #lib.css-variables();

    background-color: @base;
    color: @text;

    /* Llama logos */
    img[src="/public/ollama.png"],
    img[src="/public/shades.png"],
    img[src="/public/glasses.png"] {
      filter: @text-filter;
    }

    code,
    pre {
      background-color: @mantle;
      color: @text !important;
    }

    input {
      background-color: @mantle;
    }

    main,
    section,
    strong,
    h3,
    ul,
    button,
    li,
    li::marker {
      color: @text;
    }
    blockquote {
      color: @subtext0;
    }

    a[class~=""] {
      color: @blue;
    }

    #query,
    #filter,
    #search {
      background-color: @mantle;
      color: @text;
    }
    #readme,
    #display,
    #file-explorer {
      color: @text;
    }

    .command {
      color: @text;
    }
    .truncate {
      color: @text;
    }

    /* Tailwind */

    * {
      border-color: @surface1;
    }

    .prose {
      --tw-prose-headings: @text;
      --tw-prose-links: @accent;
    }

    .text-white,
    .text-black {
      color: @text;
    }
    .text-gray-900 {
      color: @subtext1;
    }
    .text-green-500,
    .text-emerald-500,
    .text-green-700 {
      color: @green;
    }
    .text-yellow-900 {
      color: @yellow;
    }
    .text-neutral-300,
    .text-neutral-400,
    .text-neutral-500 {
      color: @subtext0;
    }
    .text-neutral-700,
    .text-neutral-800,
    .text-neutral-900 {
      color: @subtext1 !important;
    }
    .text-red-500 {
      color: @red;
    }
    .text-blue-500,
    .text-blue-600 {
      color: @accent;
    }
    /* Models page, color for non-weight pills/tags. Background color is solid from `.bg-indigo-50`. */
    .text-indigo-600 {
      color: @crust;
    }

    .bg-neutral-100 pre,
    .bg-neutral-100 .command {
      background-color: unset !important;
    }
    .bg-white {
      background-color: @mantle;
    }
    .bg-black,
    .hover\:bg-black:hover {
      background-color: @surface0 !important;
    }
    .bg-neutral-50 {
      background-color: @surface0;
    }
    .bg-neutral-100,
    .hover\:bg-neutral-100:hover {
      background-color: @surface2 !important;
    }
    .bg-neutral-700,
    .bg-neutral-800 {
      background-color: @surface1;
    }
    .bg-green-50 {
      background-color: fade(@green, 10%);
    }
    .bg-yellow-50 {
      background-color: fade(@yellow, 10%);
    }
    .bg-indigo-50 {
      background-color: @accent;
    }
    .bg-\[\#ddf4ff\] {
      background-color: fade(@accent, 10%);
    }

    .border {
      border-color: @accent;
    }
    .border-neutral-200,
    .border-neutral-300,
    .divide-gray-200 > :not([hidden]) ~ :not([hidden]),
    .divide-neutral-200 > :not([hidden]) ~ :not([hidden]) {
      border-color: @surface1;
    }
    .focus\:border-blue-400:focus {
      border-color: @accent;
    }
    .focus\:border-red-400:focus {
      border-color: @red;
    }

    .ring-neutral-300 {
      --tw-ring-color: @surface1 !important;
    }
    .ring-green-600\/20 {
      --tw-ring-color: @green;
    }
    .ring-yellow-600\/20 {
      --tw-ring-color: @yellow;
    }
    select:focus,
    .ring-blue-300,
    .focus\:ring-blue-300:focus {
      --tw-ring-color: rgba(#lib.rgbify(@accent)[], var(--tw-ring-opacity));
    }
    .focus\:ring-red-300:focus {
      --tw-ring-color: rgba(#lib.rgbify(@red)[], var(--tw-ring-opacity));
    }
  }
}

/* ==UserStyle==
@name Perplexity Catppuccin
@namespace github.com/catppuccin/userstyles/styles/perplexity
@homepageURL https://github.com/catppuccin/userstyles/tree/main/styles/perplexity
@version 2025.09.06
@updateURL https://github.com/catppuccin/userstyles/raw/main/styles/perplexity/catppuccin.user.less
@supportURL https://github.com/catppuccin/userstyles/issues?q=is%3Aopen+is%3Aissue+label%3Aperplexity
@description Soothing pastel theme for Perplexity
@author Catppuccin
@license MIT

@preprocessor less
@var select lightFlavor "Light Flavor" ["latte:Latte*", "frappe:Frappé", "macchiato:Macchiato", "mocha:Mocha"]
@var select darkFlavor "Dark Flavor" ["latte:Latte", "frappe:Frappé", "macchiato:Macchiato", "mocha:Mocha*"]
@var select accentColor "Accent" ["rosewater:Rosewater", "flamingo:Flamingo", "pink:Pink", "mauve:Mauve*", "red:Red", "maroon:Maroon", "peach:Peach", "yellow:Yellow", "green:Green", "teal:Teal", "blue:Blue", "sapphire:Sapphire", "sky:Sky", "lavender:Lavender", "subtext0:Gray"]
==/UserStyle== */

@import "https://userstyles.catppuccin.com/lib/lib.less";

@-moz-document domain("perplexity.ai") {
  :root:not([data-color-scheme="dark"]) {
    #catppuccin(@lightFlavor);
  }
  :root,
  :root:not([data-color-scheme="light"]) {
    #catppuccin(@darkFlavor);
  }

  #catppuccin(@flavor) {
    #lib.palette();
    #lib.defaults();

    ::selection {
      background-color: fade(@accent, 30%)
        !important; // TODO:  Has !important unlike the defaults. Add !important to defaults?
      color: @text
        !important; // TODO: Another case of setting the text color in the selection.
    }

    body {
      background-color: @mantle !important;
    }
    .bg-\[red\] {
      background-color: @red !important;
    }

    .bg-alert {
      background-color: @peach !important;
    }
    .bg-text-100 {
      background-color: @text !important;
    }

    .bg-backdrop-lightbox\/95 {
      background-color: @crust !important;
    }

    .bg-backdrop\/70 {
      background-color: @mantle !important;
    }

    .bg-background, .bg-background-50 {
      background-color: @base !important;
    }

    .bg-background-100 {
      background-color: @base !important;
    }

    .bg-background-300, .bg-background-200 {
      background-color: @mantle !important;
    }

    .bg-background-super-alt {
      background-color: @accent !important;
    }

    .bg-backgroundDark {
      background-color: @surface0 !important;
    }

    .bg-black,
    .bg-black\/30,
    .bg-black\/40,
    .bg-black\/50,
    .bg-black\/60,
    .bg-black\/80 {
      background-color: @crust !important;
    }

    .bg-borderMain {
      background-color: @surface1 !important;
    }

    .bg-idle,
    .bg-idle\/70 {
      background-color: @surface0 !important;
    }

    .bg-offset,
    .bg-offsetDark,
    .bg-offset\/50 {
      background-color: @mantle !important;
    }

    .bg-offsetPlus {
      background-color: @surface0 !important;
    }

    .bg-offsetPlusDark,
    .dark\:\!bg-offsetPlusDark:where(
      [data-color-scheme="dark"] .dark\:\!bg-offsetPlusDark,
      [data-color-scheme="dark"] .dark\:\!bg-offsetPlusDark *
    ) {
      background-color: @mantle !important;
    }

    .bg-super,
    .bg-superAlt,
    .bg-superBG,
    .bg-superBGDark,
    .bg-superDark,
    .bg-superDark\/100,
    .bg-super\/100 {
      background-color: @accent !important;
    }
    .bg-super\/10,
    .bg-superDark\/10 {
      background-color: fade(@accent, 10%) !important;
    }

    .bg-textMain {
      background-color: @crust !important;
    }

    .bg-textMainDark,
    .bg-textMain\/10 {
      background-color: @text !important;
    }

    .bg-textOff {
      background-color: @subtext1 !important;
    }

    .bg-textOffDark,
    .bg-textOff\/50 {
      background-color: @subtext0 !important;
    }

    .bg-white,
    .bg-white\/30,
    .bg-white\/50,
    .bg-white\/80 {
      background-color: @text !important;
    }

    .text-background {
      color: @base !important;
    }

    .text-black {
      color: @crust !important;
    }

    .text-offset {
      color: @mantle !important;
    }

    .text-orange-400 {
      color: @peach !important;
    }

    .text-super,
    .text-superAlt,
    .text-superDark,
    .text-superDuper {
      color: @accent !important;
    }

    .text-textMain {
      color: @text !important;
    }

    .text-textMainDark,
    .text-textOff {
      color: @subtext1 !important;
    }

    .text-textOff\/50 {
      color: @subtext0 !important;
    }

    .text-textOffDark {
      color: @subtext1 !important;
    }

    .text-textOffDark\/50 {
      color: @subtext0 !important;
    }

    .text-white {
      color: @crust !important;
    }

    .text-default {
      color: @text !important;
    }

    .text-zinc-700 {
      color: @subtext1 !important;
    }

    .stroke-background {
      stroke: @surface0 !important;
    }

    .stroke-super,
    .stroke-superAlt,
    .stroke-superDark {
      stroke: @accent !important;
    }

    .stroke-textMain {
      stroke: @text !important;
    }

    .stroke-textMainDark,
    .stroke-textOff {
      stroke: @subtext1 !important;
    }

    .stroke-textOffDark {
      stroke: @subtext0 !important;
    }

    .fill-backgroundDark {
      fill: @base !important;
    }

    .fill-super,
    .fill-superAlt,
    .fill-superDark {
      fill: @accent !important;
    }

    .fill-textMain,
    .fill-textMainDark {
      fill: @text !important;
    }

    .fill-textOff,
    .fill-textOffDark {
      fill: @subtext1 !important;
    }

    .border-\[black\]\/10 {
      border-color: fade(@mantle, 10%) !important;
    }

    .border-background,
    .border-black\/10,
    .border-black\/5 {
      border-color: @mantle !important;
    }
    .dark\:border-borderMainDark:where(
      [data-color-scheme="dark"] .dark\:border-borderMainDark,
      [data-color-scheme="dark"] .dark\:border-borderMainDark *
    ),
    .border-borderMain {
      border-color: @surface1 !important;
    }

    .border-borderMain\/10,
    .border-borderMain\/50,
    .border-borderMain\/75 {
      border-color: @surface0 !important;
    }

    .border-borderMainDark {
      border-color: @base !important;
    }

    .border-offsetPlus {
      border-color: @mantle !important;
    }

    .border-super,
    .border-super\/10,
    .border-super\/100 {
      border-color: @accent !important;
    }

    .border-textMain\/0 {
      border-color: transparent !important;
    }

    .border-textMainDark {
      border-color: @mantle !important;
    }

    .border-textOff\/50 {
      border-color: @subtext0 !important;
    }

    .border-b-offset {
      border-bottom-color: @subtext0 !important;
    }
    .group:hover [class*="group-hover:text-superDark"] {
      color: @accent !important;
    }

    [class*="hover:!bg-superAlt/20"]:hover {
      background-color: @accent !important;
    }

    [class*="data-[focused=self]:bg-background-200"]:focus,
    [class*="hover:bg-background-200"]:hover {
      background-color: @crust !important;
    }

    [class*=":hover:bg-offset"]:hover, [class*="hover:bg-offset"]:hover {
      background-color: @surface0 !important;
    }

    [class*="hover:bg-offsetPlus"]:hover {
      background-color: @surface1 !important;
    }

    [class*="hover:bg-super"]:hover {
      background-color: @accent !important;
    }

    [class*="hover:text-super"]:hover,
    [class*="hover:text-superAlt"]:hover {
      color: @accent !important;
    }

    [class*="hover:text-textMain"]:hover {
      color: @text !important;
    }

    [class*="hover:text-textOff"]:hover {
      color: @subtext0 !important;
    }

    [class*="hover:text-white"]:hover {
      color: @text !important;
    }

    [data-focused="self"] {
      background-color: @surface1 !important;
    }

    .dark\:divide-borderMainDark\/50:where(
      [data-color-scheme="dark"] .dark\:divide-borderMainDark\/50,
      [data-color-scheme="dark"] .dark\:divide-borderMainDark\/50 *
    )
      > :not([hidden])
      ~ :not([hidden]),
    .divide-borderMain\/50 > :not([hidden]) ~ :not([hidden]) {
      border-color: @surface1 !important;
    }

    .focus\:\!border-backgroundDark:focus {
      border-color: @mantle !important;
    }

    .focus\:bg-background:focus {
      background-color: @base !important;
    }

    .focus\:text-super:focus {
      color: @accent !important;
    }

    .focus-visible\:bg-offsetPlus:focus-visible {
      background-color: @crust !important;
    }

    *[class*="ring"] {
      --tw-ring-color: @surface2 !important;
      --tw-ring-offset-color: @mantle !important;
    }

    .caret-superDuper {
      caret-color: @accent !important;
    }
    .data-\[state\=checked\]\:bg-super[data-state="checked"] {
      background-color: @accent !important;
    }

    /* Additional fixes: */

    .scrollbar-thumb-idle {
      --scrollbar-thumb: @surface1 !important;
    }

    /* gradient on super long prompt */
    div[style="background: linear-gradient(transparent, currentcolor);"] {
      background: linear-gradient(transparent, @base) !important;
    }

    /* citations */
    .citation:hover * {
      color: @crust !important;
    }
    /* switch knob in settings */
    .data-\[state\=checked\]\:before\:\!bg-super[data-state="checked"]::before {
      background-color: @accent !important;
    }
    /* switch in main input */
    #copilot-toggle > div::before {
      background-color: @overlay1;
    }

    /* credits on image view */
    #__next
      > div:nth-child(26)
      > div:nth-child(2)
      > div
      > div
      > div.gap-md.mx-md.py-md.border-borderMainDark.flex.h-\[74px\].items-center.justify-between.border-b-2
      > div.gap-x-md.flex.items-center
      > a
      > div
      > div
      > div.line-clamp-1.break-all.transition-all.duration-300.white.font-sans.text-sm.text-white.selection\:bg-super\/50.selection\:text-textMain.dark\:selection\:bg-superDuper\/10.dark\:selection\:text-superDark {
      color: @text !important;
    }

    /* research goals in pro search */
    .research-goal::before {
      border-color: @surface1;
    }
    .research-goal-title:hover {
      background-color: @surface0;
    }
    .research-goal-timeline {
      background-color: @surface1;
    }

    .\!bg-transparent {
      background: transparent !important;
    }
  }
}

#rgbify(@color) {
  @rgb: red(@color) green(@color) blue(@color);
}

/* ==UserStyle==
@name PyPI Catppuccin
@namespace github.com/catppuccin/userstyles/styles/pypi
@homepageURL https://github.com/catppuccin/userstyles/tree/main/styles/pypi
@version 2026.03.14
@updateURL https://github.com/catppuccin/userstyles/raw/main/styles/pypi/catppuccin.user.less
@supportURL https://github.com/catppuccin/userstyles/issues?q=is%3Aopen+is%3Aissue+label%3Apypi
@description Soothing pastel theme for PyPI
@author Catppuccin
@license MIT

@preprocessor less
@var select lightFlavor "Light Flavor" ["latte:Latte*", "frappe:Frappé", "macchiato:Macchiato", "mocha:Mocha"]
@var select darkFlavor "Dark Flavor" ["latte:Latte", "frappe:Frappé", "macchiato:Macchiato", "mocha:Mocha*"]
@var select accentColor "Accent" ["rosewater:Rosewater", "flamingo:Flamingo", "pink:Pink", "mauve:Mauve*", "red:Red", "maroon:Maroon", "peach:Peach", "yellow:Yellow", "green:Green", "teal:Teal", "blue:Blue", "sapphire:Sapphire", "sky:Sky", "lavender:Lavender", "subtext0:Gray"]
==/UserStyle== */

@import "https://userstyles.catppuccin.com/lib/lib.less";

@-moz-document domain("pypi.org") {
  @import url("https://python.catppuccin.com/pygments/catppuccin-variables.important.css");

  :root {
    @media (prefers-color-scheme: light) {
      #catppuccin(@lightFlavor);
    }
    @media (prefers-color-scheme: dark) {
      #catppuccin(@darkFlavor);
    }
  }

  #catppuccin(@flavor) {
    #lib.palette();
    #lib.defaults();
    #lib.css-variables();

    ::selection {
      color: unset; // TODO: Basically another case of setting the text color in the selection, but unsetting it here.
    }

    body {
      background-color: @base !important;
      color: @text !important;
    }

    input,
    select,
    textarea {
      background-color: @mantle !important;
      border-color: @surface0 !important;
      color: @text !important;

      &:active,
      &:focus,
      &:hover {
        border-color: @accent !important;
        box-shadow: inset 0 0 0 1px @accent !important;
      }
    }

    input:disabled,
    select:disabled {
      &,
      &:active,
      &:focus,
      &:hover {
        background-color: @mantle !important;
      }
    }

    hr {
      background-color: @surface0 !important;
      background-image: linear-gradient(90deg, @surface0, @surface0) !important;
    }

    .project-description blockquote {
      color: @subtext0 !important;
    }

    .project-description table {
      tr {
        background-color: @base !important;
      }

      tr:nth-child(odd) {
        background-color: @mantle !important;
      }

      &, tr, th, td {
        border-color: @surface0 !important;
      }
    }

    .verified .check {
      color: @green;
    }

    .banner,
    .footer {
      background-color: @mantle !important;
      color: @text !important;
    }

    .accordion__link {
      color: @accent !important;
    }

    .password-strength {
      border-color: @surface2 !important;
    }

    .accordion__link:active,
    .accordion__link:focus {
      outline-color: @accent !important;
      outline-style: solid;
    }

    @media (max-width: 1000px) {
      .accordion__link {
        color: @text !important;
      }

      .accordion__link:active,
      .accordion__link:focus {
        outline-color: @text !important;
      }
    }

    .footer__divider {
      border-color: @surface0 !important;
    }

    a,
    .footer__menu li a {
      &:active,
      &:focus {
        outline-color: @accent !important;
      }
    }

    .skip-to-content:focus {
      background-color: @base !important;
      color: @text !important;
    }

    a:not(.site-header__logo, .button, .dropdown__link, .badge, .release__card),
    a:hover:not(
      .site-header__logo,
      .button,
      .dropdown__link,
      .badge,
      .release__card
    ),
    .footer__menu li a,
    .footer__text a,
    .language-switcher ul button {
      color: @accent !important;
    }

    .footer__text a,
    .language-switcher ul button {
      &:active,
      &:focus {
        outline-color: @accent !important;
      }
    }

    .footer__menu h2,
    .footer__text,
    .language-switcher ul button.language-switcher__selected::before {
      color: @text !important;
    }

    .language-switcher {
      background-color: @crust !important;
      border-top-color: @crust !important;
      color: @text !important;
    }

    .horizontal-section--grey {
      background-color: @base !important;
      border-bottom-color: @base !important;
      border-top-color: @base !important;
    }

    .statistics-bar__statistic {
      color: @subtext0 !important;
    }

    .lede-paragraph {
      color: @subtext1 !important;
    }

    .site-header {
      background-color: @crust !important;
      border-bottom-color: @crust !important;
    }

    .site-header__logo:active,
    .site-header__logo:focus {
      outline-color: @text !important;
    }

    .dropdown__content {
      border-color: @accent !important;
      box-shadow: none !important;
    }

    .dropdown__content li:hover {
      background-color: @base !important;
    }

    .dropdown button.dropdown__link:not(:hover),
    .dropdown__link {
      background-color: @crust !important;
      border-bottom-color: @crust !important;
      color: @text !important;
    }

    .dropdown__link:hover {
      background-color: @base !important;
    }

    a.dropdown__link,
    a.dropdown__link:hover {
      background-image: none !important;
      color: @text !important;
    }

    .horizontal-menu__link:active,
    .horizontal-menu__link:focus {
      outline-color: @accent !important;
    }

    .horizontal-menu--light .horizontal-menu__link {
      color: @accent !important;
    }

    .horizontal-menu--light .horizontal-menu__link:hover {
      text-decoration-color: @accent !important;
    }

    .sponsors,
    .sidebar-section.loaded {
      display: none;
    }

    .package-snippet {
      background-color: @crust !important;
      border-color: @surface0 !important;
      box-shadow: none !important;
